fn paginate_results(page_number: i32, page_size: i32) -> Result<Vec<String>, String> {
    if page_number <= 0 {
        return Err("Invalid page number: must be positive.".to_string());
    }
    if page_size <= 0 {
        return Err("Invalid page size: must be positive.".to_string());
    }

    let data: Vec<String> = (1..=100).map(|i| format!("Item {}", i)).collect();
    let start = ((page_number - 1) * page_size) as usize;
    let page_size = page_size as usize;

    if start >= data.len() {
        return Ok(Vec::new());
    }

    let end = (start + page_size).min(data.len());
    Ok(data[start..end].to_vec())
}
