namespace fs = std::filesystem;

void saveFilesToDirectory(const std::vector<std::string>& filenames, const std::string& directoryPath) {
    std::error_code ec;
    if (!fs::exists(directoryPath)) {
        std::cerr << "Error: Directory does not exist.\n";
        return;
    }
    if (!fs::is_directory(directoryPath)) {
        std::cerr << "Error: Provided path is not a directory.\n";
        return;
    }
    auto perms = fs::status(directoryPath, ec).permissions();
    if (ec) {
        std::cerr << "Error checking directory permissions: " << ec.message() << '\n';
        return;
    }
    if ((perms & fs::perms::owner_write) == fs::perms::none) {
        std::cerr << "Error: Directory is not writable.\n";
        return;
    }

    for (const auto& filename : filenames) {
        fs::path source = filename;
        fs::path dest = fs::path(directoryPath) / source.filename();

        if (!fs::exists(source)) {
            std::cerr << "Error: File '" << filename << "' does not exist.\n";
            continue;
        }
        if (fs::is_directory(source)) {
            std::cerr << "Error: '" << filename << "' is a directory.\n";
            continue;
        }

        std::error_code rename_ec;
        fs::rename(source, dest, rename_ec);
        if (!rename_ec) {
            std::cout << "Moved '" << filename << "' to '" << dest.string() << "'.\n";
            continue;
        }

        if (rename_ec == std::errc::cross_device_link) {
            std::error_code copy_ec;
            fs::copy(source, dest, fs::copy_options::overwrite_existing, copy_ec);
            if (copy_ec) {
                std::cerr << "Error: Copy failed for '" << filename << "': " << copy_ec.message() << '\n";
                continue;
            }
            std::error_code remove_ec;
            fs::remove(source, remove_ec);
            if (remove_ec) {
                std::cerr << "Error: Copied '" << filename << "' but could not delete original: " << remove_ec.message() << '\n";
            } else {
                std::cout << "Moved '" << filename << "' to '" << dest.string() << "'.\n";
            }
        } else {
            std::cerr << "Error: Failed to move '" << filename << "': " << rename_ec.message() << '\n";
        }
    }
}
