import java.io.File;
import java.io.IOException;
import javax.xml.parsers.DocumentBuilder;
import javax.xml.parsers.DocumentBuilderFactory;
import javax.xml.parsers.ParserConfigurationException;
import org.w3c.dom.Document;
import org.w3c.dom.NodeList;
import org.xml.sax.SAXException;

public class ConfigLoader {
    public static ServerConfig loadConfiguration(String filePath) throws IOException {
        try {
            Document doc = DocumentBuilderFactory.newInstance()
                    .newDocumentBuilder()
                    .parse(new File(filePath));
            doc.getDocumentElement().normalize();

            String portStr = getTagValue("port", doc);
            String timeoutStr = getTagValue("timeout", doc);

            ServerConfig config = new ServerConfig();
            config.setPort(parseInteger(portStr, "port"));
            config.setTimeout(parseInteger(timeoutStr, "timeout"));
            return config;
        } catch (FileNotFoundException e) {
            throw new IOException("Configuration file not found: " + filePath, e);
        } catch (ParserConfigurationException e) {
            throw new IOException("XML parser configuration error", e);
        } catch (SAXException e) {
            throw new IOException("Invalid XML format in configuration file", e);
        } catch (IllegalArgumentException e) {
            throw new IOException("Configuration error: " + e.getMessage(), e);
        }
    }

    private static String getTagValue(String tag, Document doc) {
        NodeList nodeList = doc.getElementsByTagName(tag);
        if (nodeList.getLength() == 0) {
            throw new IllegalArgumentException("Missing tag: " + tag);
        }
        return nodeList.item(0).getTextContent().trim();
    }

    private static int parseInteger(String value, String tagName) {
        try {
            return Integer.parseInt(value);
        } catch (NumberFormatException e) {
            throw new IllegalArgumentException("Invalid integer value for tag '" + tagName + "': " + value);
        }
    }
}

