pub fn filter_above_threshold(values: Vec<Value>, threshold: i32) -> Result<Vec<Value>, Box<dyn Error>> {
    for value in &values {
        match value {
            Value::Number(_) => {},
            _ => return Err("Non-numeric or nil value found".into()),
        }
    }
    let filtered = values.into_iter().filter(|v| {
        if let Value::Number(n) = v {
            n.to_f64() <= threshold as f64
        } else {
            false
        }
    }).collect();
    Ok(filtered)
