    if not isinstance(search_query, str):
        raise TypeError("Search query must be a string.")
    if not search_query:
        raise ValueError("Search query cannot be empty.")

    # Validate documents is a non-empty list of non-empty strings
    if not isinstance(documents, list):
        raise TypeError("Documents must be provided as a list.")
    if not documents:
        raise ValueError("Documents list cannot be empty.")
    for idx, doc in enumerate(documents):
        if not isinstance(doc, str):
            raise TypeError(f"Document at index {idx} is not a string.")
        if not doc:
            raise ValueError(f"Document at index {idx} is an empty string.")

    # Perform case-insensitive search and return matching documents
    query_lower = search_query.lower()
    return [doc for doc in documents if query_lower in doc.lower()]
