using namespace std;

void traverseGraph(const vector<vector<int>>& adjMatrix, int startNode) {
    if (adjMatrix.empty()) {
        cerr << "Error: Adjacency matrix is empty." << endl;
        return;
    }
    int n = adjMatrix.size();
    for (const auto& row : adjMatrix) {
        if (row.size() != n) {
            cerr << "Error: Adjacency matrix is not square." << endl;
            return;
        }
    }
    if (startNode < 0 || startNode >= n) {
        cerr << "Error: Starting node index is out of bounds." << endl;
        return;
    }
    vector<bool> visited(n, false);
    queue<int> q;
    vector<int> order;
    visited[startNode] = true;
    q.push(startNode);
    while (!q.empty()) {
        int u = q.front();
        q.pop();
        order.push_back(u);
        for (int v = 0; v < n; ++v) {
            if (adjMatrix[u][v] != 0 && !visited[v]) {
                visited[v] = true;
                q.push(v);
            }
        }
    }
    for (size_t i = 0; i < order.size(); ++i) {
        if (i > 0) cout << " ";
        cout << order[i];
    }
    cout << endl;
}
