/**
 * @brief Processes a singly linked list, multiplying each node's value by its 1-indexed position.
 * 
 * @param head Pointer to the head node of the linked list.
 * @return Node* Pointer to the head of the modified linked list. Returns nullptr if input is empty.
 */
Node* processLinkedList(Node* head) {
    if (!head) return nullptr; // Handle empty list case

    Node* current = head;
    int position = 1;
    while (current) {
        current->val *= position; // Multiply value by current position
