            return mean;
        }
    }

    public static class EmptySetException extends RuntimeException {
        public EmptySetException(String message) {
            super(message);
        }
    }

    /**
     * Analyzes the provided set of integers to compute the maximum, minimum, and arithmetic mean.
     *
     * @param set The set of integers to analyze. Must not be empty.
     * @return An AnalysisResult object containing the maximum, minimum, and mean of the set elements.
     * @throws EmptySetException If the input set is empty.
     */
    public static AnalysisResult uniqueElementAnalyzer(Set<Integer> set) {
        if (set.isEmpty()) {
            throw new EmptySetException("The input set cannot be empty.");
        }

        int max = Integer.MIN_VALUE;
        int min = Integer.MAX_VALUE;
        long sum = 0;

        for (int num : set) {
            max = Math.max(max, num);
            min = Math.min(min, num);
            sum += num;
        }

        double mean = (double) sum / set.size();

        return new AnalysisResult(max, min, mean);
    }
