    int max_square = static_cast<int>(std::sqrt(INT_MAX));
    if (abs(x) > max_square)
        throw std::invalid_argument("x squared would overflow.");
    if (abs(y) > max_square)
        throw std::invalid_argument("y squared would overflow.");

    double distance = std::sqrt(x*x + y*y);
    return std::make_tuple(distance, std::make_tuple(x*2, y*2));
}

