use std::collections::{HashMap, VecDeque, HashSet};

#[derive(Debug)]
pub enum PathError {
    NodeNotFound,
    NoPath,
}

#[derive(PartialEq, Eq, Hash, Clone)]
pub struct Node(String);

pub struct Graph {
    adjacency_list: HashMap<Node, Vec<Node>>,
}

pub enum TraversalMethod {
    DFS,
    BFS,
}

pub fn find_path(
    graph: &Graph,
    start: &Node,
    end: &Node,
    method: TraversalMethod,
) -> Result<Vec<Node>, PathError> {
    if !graph.adjacency_list.contains_key(start) || !graph.adjacency_list.contains_key(end) {
        return Err(PathError::NodeNotFound);
    }

    let mut visited = HashSet::new();
    let mut predecessors = HashMap::new();
    let mut frontier = VecDeque::new();
    frontier.push_back(start.clone());
    visited.insert(start.clone());

    while let Some(current_node) = match method {
        TraversalMethod::DFS => frontier.pop_back(),
        TraversalMethod::BFS => frontier.pop_front(),
    } {
        if current_node == *end {
            let mut path = vec![current_node];
            let mut current = &path[0];
            while let Some(predecessor) = predecessors.get(current) {
                path.push(predecessor.clone());
                current = predecessor;
            }
            path.reverse();
            return Ok(path);
        }

        if let Some(neighbors) = graph.adjacency_list.get(&current_node) {
            for neighbor in neighbors {
                if !visited.contains(neighbor) {
                    visited.insert(neighbor.clone());
                    predecessors.insert(neighbor.clone(), current_node.clone());
                    frontier.push_back(neighbor.clone());
                }
            }
        }
    }

    Err(PathError::NoPath)
}
