using namespace std;

vector<int> findShortestPath(const unordered_map<int, vector<pair<int, int>>>& graph, int start, int end) {
    if (graph.find(start) == graph.end() || graph.find(end) == graph.end()) {
        throw invalid_argument("Start or end node not in graph");
    }

    unordered_map<int, int> dist;
    unordered_map<int, int> prev;

    for (const auto& entry : graph) {
        dist[entry.first] = INT_MAX;
    }
    dist[start] = 0;

    priority_queue<pair<int, int>, vector<pair<int, int>>, greater<pair<int, int>>> pq;
    pq.push({0, start});

    while (!pq.empty()) {
        auto current = pq.top();
        int current_dist = current.first;
        int u = current.second;
        pq.pop();

        if (current_dist > dist[u]) continue;

        if (u == end) break;

        const auto& neighbors = graph.at(u);
        for (const auto& neighbor : neighbors) {
            int v = neighbor.first;
            int weight = neighbor.second;

            int alt = dist[u] + weight;
            if (alt < dist[v]) {
                dist[v] = alt;
                prev[v] = u;
                pq.push({alt, v});
            }
        }
    }

    if (dist[end] == INT_MAX) return {};

    vector<int> path;
    int current_node = end;
    while (current_node != start) {
        path.push_back(current_node);
        current_node = prev[current_node];
    }
    path.push_back(start);
    reverse(path.begin(), path.end());

    return path;
}
