public class GraphTraversal {
    private static final Logger LOGGER = Logger.getLogger(GraphTraversal.class.getName());

    public static <T> List<T> analyzeGraphTraversal(Map<T, List<T>> graph, boolean useBFS) {
        if (graph == null) {
            LOGGER.severe("Graph cannot be null.");
            throw new IllegalArgumentException("Graph cannot be null.");
        }

        List<T> visitedOrder = new ArrayList<>();
        Set<T> visited = new HashSet<>();

        for (T node : graph.keySet()) {
            if (!visited.contains(node)) {
                String method = useBFS ? "BFS" : "DFS";
                LOGGER.info(String.format("Starting %s from node: %s", method, node));
                if (useBFS) {
                    bfs(graph, node, visited, visitedOrder);
                } else {
                    dfs(graph, node, visited, visitedOrder);
                }
            }
        }

        return visitedOrder;
    }

    private static <T> void bfs(Map<T, List<T>> graph, T startNode, Set<T> visited, List<T> visitedOrder) {
        Queue<T> queue = new LinkedList<>();
        visited.add(startNode);
        queue.add(startNode);

        while (!queue.isEmpty()) {
            T current = queue.poll();
            visitedOrder.add(current);
            for (T neighbor : graph.getOrDefault(current, Collections.emptyList())) {
                if (!visited.contains(neighbor)) {
                    visited.add(neighbor);
                    queue.add(neighbor);
                }
            }
        }
    }

    private static <T> void dfs(Map<T, List<T>> graph, T startNode, Set<T> visited, List<T> visitedOrder) {
        Deque<T> stack = new ArrayDeque<>();
        stack.push(startNode);

        while (!stack.isEmpty()) {
            T current = stack.pop();
            if (!visited.contains(current)) {
                visited.add(current);
                visitedOrder.add(current);
                List<T> neighbors = graph.getOrDefault(current, Collections.emptyList());
                for (int i = neighbors.size() - 1; i >= 0; i--) {
                    T neighbor = neighbors.get(i);
                    if (!visited.contains(neighbor)) {
                        stack.push(neighbor);
                    }
                }
            }
        }
    }
}
