    int n = graph.size();
    if (startNode < 0 || startNode >= n) {
        throw invalid_argument("Invalid starting node");
    }
    for (const auto& row : graph) {
        if (row.size() != n) {
            throw invalid_argument("Invalid adjacency matrix");
        }
