    for (const auto& key : schema.keys()) {
        std::string columnDef = schema[key].toString();
        std::string query = "ALTER TABLE " + tableName + " ADD COLUMN " + key + " " + columnDef + ";";
        try {
            executeQuery(query);
        } catch (const std::exception& e) {
            throw std::runtime_error("Schema update failed: " + std::string(e.what()));
        }
    }
}
